    <li><?php echo erTranslationClassLhTranslation::getInstance()->getTranslation('genericbot/helpattributes', 'For each next message gap, time is added only if gap is greater than 0 and smaller than timeout. Visitor messages can increase current owner\'s time while ownership does not change.');?></li>
