    <li><?php echo erTranslationClassLhTranslation::getInstance()->getTranslation('genericbot/helpattributes', 'If the gap between two messages is larger than the timeout below, that gap is skipped — so a long silence does not unfairly inflate an agent\'s time.');?></li>
