    <li><?php echo \erLhcoreClassModelChatConfig::fetch('cduration_timeout_operator')->current_value ?> <?php echo erTranslationClassLhTranslation::getInstance()->getTranslation('genericbot/helpattributes', 'minutes — max gap allowed after an agent message. If the visitor replied later than this, that waiting time is ignored.');?></li>
